import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.filter.js";
import "core-js/modules/es.iterator.reduce.js";
import "core-js/modules/web.url-search-params.delete.js";
import "core-js/modules/web.url-search-params.has.js";
import "core-js/modules/web.url-search-params.size.js";
import "@/assets/styles/AdminPage.css";
import logo from "@/assets/logo.jpeg";
import axios from "@/utils/axios";
import socket from "@/socket";
import AddProduct from "@/views/AddProduct.vue";
import ProductList from "@/views/ProductList.vue";
import ProductEdit from "@/views/ProductEdit.vue";
import ProductCategory from "@/views/AddCategory.vue";
import StaffManagement from "@/views/StaffManagement.vue";
// eslint-disable-next-line no-unused-vars
import AdminOrders from "@/views/AdminOrders.vue";
import AdminLeaves from "@/views/AdminLeaves.vue";
import ChatWindow from "@/views/ChatWindow.vue";
import LiveTracking from "@/views/LiveTracking.vue";
import AdminAttendance from "@/views/AdminAttendance.vue";
import AttendanceAnalysis from "@/views/AttendanceAnalysis.vue";
import AlgorithmComparison from "@/views/AlgorithmComparison.vue";
const API_BASE_URL = "/api";
export default {
  name: "AdminPage",
  components: {
    AddProduct,
    ProductList,
    ProductEdit,
    ProductCategory,
    StaffManagement,
    AdminOrders,
    AdminLeaves,
    ChatWindow,
    LiveTracking,
    AdminAttendance,
    AttendanceAnalysis,
    AlgorithmComparison
  },
  data() {
    return {
      selectedMenu: "dashboard",
      isSidebarOpen: true,
      showAddProductModal: false,
      showListProductsModal: false,
      showEditProductModal: false,
      editProductId: null,
      dashboardLoading: false,
      // Stats
      totalProducts: 0,
      totalCategories: 0,
      totalStaff: 0,
      activeStaff: 0,
      pendingLeaves: 0,
      approvedLeaves: 0,
      totalInventory: 0,
      unreadMessageCount: 0,
      totalEnquiries: 0,
      pendingReviews: 0,
      totalPurchases: 0,
      totalProfit: 0,
      totalOrders: 0,
      salesTimeframe: "all",
      analyticsData: null,
      chartTimeframe: "today",
      displayedPurchases: 0,
      displayedProfit: 0,
      productOverview: [],
      productOverviewLoading: false,
      reviewsLoading: false,
      currentReviews: [],
      actionLoading: false,
      reportLoading: false,
      messageInterval: null,
      topProductsInterval: null,
      // Top Products
      topProducts: [],
      topProductsLoading: false,
      // Expiry & Alerts
      expiringProducts: [],
      expiredCount: 0,
      showExpiryDetails: false,
      // Analytics
      salesChartType: 'table',
      customStartDate: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      customEndDate: new Date().toISOString().split('T')[0],
      // Password Change
      passwordForm: {
        currentPassword: "",
        newPassword: "",
        confirmPassword: ""
      },
      passwordError: "",
      passwordSuccess: "",
      passwordLoading: false,
      logo
    };
  },
  mounted() {
    // Initialize sidebar state based on screen width
    if (window.innerWidth <= 1024) {
      this.isSidebarOpen = false;
    }
    this.fetchDashboardStats();
    this.fetchUnreadMessages();
    this.fetchTopProducts();
    this.fetchProductOverview();
    this.messageInterval = setInterval(() => {
      this.fetchUnreadMessages();
    }, 10000);
    this.topProductsInterval = setInterval(() => {
      this.fetchTopProducts();
    }, 30000);

    // Socket listeners for real-time updates
    socket.on("productAdded", () => {
      this.fetchDashboardStats();
    });
    socket.on("productUpdated", () => {
      this.fetchDashboardStats();
    });
    socket.on("productDeleted", () => {
      this.fetchDashboardStats();
    });
    socket.on("categoryAdded", () => {
      this.fetchDashboardStats();
    });
    socket.on("categoryUpdated", () => {
      this.fetchDashboardStats();
    });
    socket.on("categoryDeleted", () => {
      this.fetchDashboardStats();
    });
    socket.on("orderPlaced", () => {
      this.fetchDashboardStats();
      this.fetchTopProducts();
    });
  },
  beforeUnmount() {
    if (this.messageInterval) clearInterval(this.messageInterval);
    if (this.topProductsInterval) clearInterval(this.topProductsInterval);

    // Remove socket listeners
    socket.off("productAdded");
    socket.off("productUpdated");
    socket.off("productDeleted");
    socket.off("categoryAdded");
    socket.off("categoryUpdated");
    socket.off("categoryDeleted");
    socket.off("orderPlaced");
  },
  watch: {
    selectedMenu(newVal) {
      if (newVal === "reviews") {
        this.fetchReviews();
      }
      if (newVal === "dashboard") {
        this.fetchDashboardStats();
      }
    },
    totalPurchases() {
      // data updated, table re-renders reactively
    },
    chartTimeframe(newVal) {
      if (newVal === 'today') {
        this.fetchDashboardStats();
      }
    }
  },
  methods: {
    async fetchProductOverview() {
      this.productOverviewLoading = true;
      try {
        const res = await axios.get(`${API_BASE_URL}/orders/admin/product-overview`);
        if (res.data.success) {
          this.productOverview = res.data.overview;
        }
      } catch (e) {
        console.error("fetchProductOverview error:", e);
      } finally {
        this.productOverviewLoading = false;
      }
    },
    async fetchTopProducts() {
      this.topProductsLoading = this.topProducts.length === 0;
      try {
        const res = await axios.get(`${API_BASE_URL}/orders/admin/top-products`);
        if (res.data && res.data.topProducts) {
          this.topProducts = res.data.topProducts;
        }
      } catch (e) {
        console.error("fetchTopProducts error:", e);
      } finally {
        this.topProductsLoading = false;
      }
    },
    getImageUrl(path) {
      if (!path) return 'https://via.placeholder.com/48x48/f1f5f9/94a3b8?text=N%2FA';
      // If path already starts with / or http, use it as is
      if (path.startsWith('/') || path.startsWith('http')) return path;
      // Otherwise add leading slash
      return `/${path}`;
    },
    manageProduct(productId) {
      this.editProductId = productId;
      this.showEditProductModal = true;
    },
    handleTimeframeChange() {
      this.fetchDashboardStats();
    },
    async downloadReport() {
      this.reportLoading = true;
      try {
        let url = `${API_BASE_URL}/orders/admin/generate-report?timeframe=${this.chartTimeframe}`;
        if (this.chartTimeframe === 'custom') {
          url += `&startDate=${this.customStartDate}&endDate=${this.customEndDate}`;
        }
        const response = await axios.get(url, {
          responseType: 'blob'
        });
        const blob = new Blob([response.data], {
          type: 'application/pdf'
        });
        const link = document.createElement('a');
        link.href = window.URL.createObjectURL(blob);
        link.download = `sales_report_${this.chartTimeframe}_${new Date().toISOString().split('T')[0]}.pdf`;
        link.click();
      } catch (e) {
        console.error("Download error:", e);
        alert("Failed to generate report");
      } finally {
        this.reportLoading = false;
      }
    },
    initCharts() {
      // Charts are no longer used in this view
      return;
    },
    getPageTitle(menu) {
      const titles = {
        dashboard: "Dashboard Overview",
        addProduct: "Add New Product",
        listProducts: "Product Catalog",
        addCategory: "Category Management",
        staffManagement: "Staff Management",
        orders: "Order Management",
        "approve-leaves": "Leave Requests",
        chat: "Messages & Communications",
        changePassword: "Change Password",
        tracking: "Live Vehicle Tracking",
        attendance: "Staff Attendance Monitoring",
        "attendance-analysis": "Attendance Analysis & Trends",
        "algorithm-comparison": "ML Algorithm Comparative Analysis"
      };
      return titles[menu] || "Dashboard";
    },
    selectMenu(menu) {
      this.selectedMenu = menu;
      this.isSidebarOpen = false;
    },
    openAddProductModal() {
      this.showAddProductModal = true;
      this.isSidebarOpen = false;
    },
    openListProductsModal() {
      this.showListProductsModal = true;
      this.isSidebarOpen = false;
    },
    async handleChangePassword() {
      this.passwordError = "";
      this.passwordSuccess = "";
      if (this.passwordForm.newPassword !== this.passwordForm.confirmPassword) {
        this.passwordError = "New passwords do not match.";
        return;
      }
      this.passwordLoading = true;
      try {
        const res = await axios.post(`${API_BASE_URL}/auth/change-password`, {
          currentPassword: this.passwordForm.currentPassword,
          newPassword: this.passwordForm.newPassword
        });
        this.passwordSuccess = res.data.msg || "Password changed successfully.";
        this.passwordForm = {
          currentPassword: "",
          newPassword: "",
          confirmPassword: ""
        };
      } catch (err) {
        this.passwordError = err.response?.data?.msg || "Failed to change password.";
      } finally {
        this.passwordLoading = false;
      }
    },
    async fetchDashboardStats() {
      this.dashboardLoading = true;
      try {
        let salesUrl = `${API_BASE_URL}/orders/admin/sales-analytics?timeframe=${this.chartTimeframe}`;
        if (this.chartTimeframe === 'custom') {
          salesUrl += `&startDate=${this.customStartDate}&endDate=${this.customEndDate}`;
        } else if (this.chartTimeframe === 'today') {
          salesUrl += `&date=${new Date().toISOString().split('T')[0]}`;
        }
        const [productsRes, categoriesRes, staffRes, leavesRes, reviewsRes, salesRes] = await Promise.all([axios.get(`${API_BASE_URL}/products/getproduct`), axios.get(`${API_BASE_URL}/categories`), axios.get(`${API_BASE_URL}/staff`), axios.get(`${API_BASE_URL}/leaves/all`), axios.get(`${API_BASE_URL}/reviews/admin/pending`), axios.get(salesUrl)]);
        if (productsRes.data.success && productsRes.data.products) {
          this.totalProducts = productsRes.data.products.length;
          this.totalInventory = productsRes.data.products.reduce((sum, p) => sum + (p.quantity || 0), 0);

          // Expiry logic
          const now = new Date();
          const tenDaysLater = new Date(now.getTime() + 10 * 24 * 60 * 60 * 1000);
          this.expiringProducts = productsRes.data.products.filter(p => {
            const exp = new Date(p.expiryDate);
            return exp > now && exp <= tenDaysLater;
          });
          this.expiredCount = productsRes.data.products.filter(p => {
            return new Date(p.expiryDate) < now;
          }).length;
        }
        if (Array.isArray(categoriesRes.data)) {
          this.totalCategories = categoriesRes.data.length;
        }
        if (staffRes.data.success && Array.isArray(staffRes.data.staff)) {
          this.totalStaff = staffRes.data.staff.length;
          this.activeStaff = staffRes.data.staff.filter(s => s.status === "active").length;
        }
        if (Array.isArray(leavesRes.data)) {
          this.pendingLeaves = leavesRes.data.filter(l => l.status === "Pending").length;
          this.approvedLeaves = leavesRes.data.filter(l => l.status === "Approved").length;
        }
        if (Array.isArray(reviewsRes.data)) {
          this.pendingReviews = reviewsRes.data.length;
        }
        if (salesRes.data) {
          this.analyticsData = salesRes.data;
          this.totalPurchases = salesRes.data.totalPurchases || 0;
          this.totalProfit = salesRes.data.totalProfit || 0;
          this.totalOrders = salesRes.data.totalOrders || 0;
        }
        this.$nextTick(() => {
          this.initCharts();
        });
      } catch (error) {
        console.error("Error loading stats:", error);
      } finally {
        this.dashboardLoading = false;
      }
    },
    async fetchUnreadMessages() {
      try {
        const res = await axios.get("/api/messages/unread-count");
        if (res.data.success) this.unreadMessageCount = res.data.unreadCount;
      } catch (e) {
        console.error("Msg Error", e);
      }
    },
    async logout() {
      try {
        await axios.post("/api/auth/logout");
      } catch (err) {
        console.error("Logout error:", err);
      } finally {
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        this.$router.push("/");
      }
    },
    closeAddProductModal() {
      this.showAddProductModal = false;
      this.fetchDashboardStats();
    },
    closeListProductsModal() {
      this.showListProductsModal = false;
      this.fetchDashboardStats();
    },
    openEditProductModal(id) {
      this.editProductId = id;
      this.showEditProductModal = true;
    },
    handleProductUpdated() {
      this.showEditProductModal = false;
      this.showListProductsModal = false;
      this.fetchDashboardStats();
    },
    async fetchReviews() {
      this.reviewsLoading = true;
      try {
        const res = await axios.get("/api/reviews/admin/all");
        if (res.data.success) {
          this.currentReviews = res.data.reviews;
        }
      } catch (err) {
        console.error("Error fetching reviews:", err);
      } finally {
        this.reviewsLoading = false;
      }
    },
    async deleteReview(id) {
      if (!confirm("Are you sure you want to delete this review?")) return;
      this.actionLoading = true;
      try {
        const res = await axios.delete(`/api/reviews/admin/delete/${id}`);
        if (res.data.success) {
          this.fetchReviews();
          this.fetchDashboardStats();
        }
      } catch (err) {
        console.error("Error deleting review:", err);
        alert("Failed to delete review");
      } finally {
        this.actionLoading = false;
      }
    },
    formatDate(date) {
      return new Date(date).toLocaleDateString("en-IN", {
        day: "numeric",
        month: "short",
        year: "numeric"
      });
    }
  }
};
